function showNotification(e,t){if(window.notyf)switch(e){case"success":notyf.success(t);break;case"error":notyf.error(t);break;case"warning":notyf.open({type:"warning",message:t});break;case"info":notyf.open({type:"info",message:t});break;default:notyf.success(t)}}function toNumber(e){if(!e)return 0;let t=Number(e.replace(/\./g,"").replace(/\,/g,"."));return isNaN(t)?0:t}function toDate(e){if(!e)return"";const[t,r,n]=e.split("/").map(Number);if(t>0&&r>0&&n>0){const e=new Date(n,r-1,t);return isNaN(e)?"":e.toISOString().split("T")[0]}}function formatValue(e,t,r=2){let n=e;if(t){switch(t){case"currency":n=Number(e)||0,n=n.toLocaleString("pt-BR",{style:"currency",currency:"BRL",minimumFractionDigits:r});break;case"m2":n=Number(e)||0,n=n.toLocaleString("pt-BR",{minimumFractionDigits:r}),n=`${n} m²`;break;case"number":n=Number(e)||0,n=n.toLocaleString("pt-BR",{minimumFractionDigits:r});break;case"percent":n=Number(e)||0,n=n.toLocaleString("pt-BR",{style:"percent"});break;case"percent2":n=Number(e)||0,n=n.toLocaleString("pt-BR",{style:"percent",minimumFractionDigits:r});break;case"datetime":const t=new Date(e);isNaN(t.getTime())||(n=t.toLocaleString("pt-br"));break;case"date":if(!e)return"";const[a,i,c]=e.split("-").map(Number);if(c>0&&i>0&&a>0){const e=new Date(a,i-1,c);isNaN(e.getTime())||(n=e.toLocaleDateString("pt-br"))}break;case"cnpj":if(14===!e.length)return"";n=e.replace(/(\d{2})(\d{3})(\d{3})(\d{4})(\d{2})/,"$1.$2.$3/$4-$5");break}return n}}function compareIgnoringAccents(e,t){const r=e=>e.normalize("NFD").replace(/[\u0300-\u036f]/g,"").toLowerCase();return r(e)===r(t)}